package tsgenerated

import (
	"encoding/hex"
	"testing"

	"github.com/bsv-blockchain/go-sdk/transaction"
	"github.com/stretchr/testify/require"
)

/*
ParentBEEF contains a transaction on testnet that sends funds to testusers.Alice (identityKey: 0320bbfb879bbd6761ecd2962badbb41ba9d60ca88327d78b07ae7141af6b6c810)
Address: mvpQZzaN5wMBeMtDjvDTLy8HJd7boN5hf2
DerivationPrefix: Pr==
DerivationSuffix: Su==
SenderIdentityKey: fixtures.AnyoneIdentityKey (0279be667ef9dcbbac55a06295ce870b07029bfcdb2dce28d959f2815b16f81798)
OutputIndex: 0

https://test.whatsonchain.com/tx/756754d5ad8f00e05c36d89a852971c0a1dc0c10f20cd7840ead347aff475ef6
*/
const (
	ParentBEEF                  = ""
	ParentBEEFTxID              = "756754d5ad8f00e05c36d89a852971c0a1dc0c10f20cd7840ead347aff475ef6"
	BeefToInternalizeHeight     = 1653933
	BeefToInternalizeMerkleRoot = "6ee2e72ad8ca8db54d8272875d4b6a53f3afe194d82c1f71369a2983f6a343c8"
)

func ParentTransaction(t testing.TB) *transaction.Transaction {
	beefBytes, err := hex.DecodeString(ParentBEEF)
	require.NoError(t, err)

	beef, err := transaction.NewBeefFromBytes(beefBytes)
	require.NoError(t, err)

	return beef.FindTransaction(ParentBEEFTxID)
}

func ParentTransactionAtomicBeef(t testing.TB) []byte {
	parentTx := ParentTransaction(t)

	atomicBeef, err := parentTx.AtomicBEEF(false)
	require.NoError(t, err)

	return atomicBeef
}
